var ids=rawData.rows.map(function(r){return 'S'+r.id;});
var means=rawData.rows.map(function(r){return Number(r.m);});
var ranges=rawData.rows.map(function(r){return Number(r.r);});
var n=Number(rawData.subgroup_size)||5;
var factors={2:{A2:1.880,D3:0,D4:3.267},3:{A2:1.023,D3:0,D4:2.574},4:{A2:0.729,D3:0,D4:2.282},5:{A2:0.577,D3:0,D4:2.114},6:{A2:0.483,D3:0,D4:2.004},7:{A2:0.419,D3:0.076,D4:1.924},8:{A2:0.373,D3:0.136,D4:1.864},9:{A2:0.337,D3:0.184,D4:1.816},10:{A2:0.308,D3:0.223,D4:1.777}};
var f=factors[n]||factors[5];
function avg(arr){var s=0;for(var i=0;i<arr.length;i++)s+=Number(arr[i])||0;return arr.length?s/arr.length:0;}
function minmax(arr){var mn=Infinity,mx=-Infinity;for(var i=0;i<arr.length;i++){var v=Number(arr[i]);if(isFinite(v)){if(v<mn)mn=v;if(v>mx)mx=v;}}if(!isFinite(mn)||!isFinite(mx)){mn=0;mx=1;}if(mn===mx){mn-=1;mx+=1;}return [mn,mx];}
function promote(levels,reasons,idx,level,reason){if(idx<0||idx>=levels.length)return;if(level>levels[idx])levels[idx]=level;if(reasons[idx].indexOf(reason)<0)reasons[idx].push(reason);}
var cl_x=avg(means);
var cl_r=avg(ranges);
var spanX=f.A2*cl_r;
var ucl_x=cl_x+spanX;
var lcl_x=cl_x-spanX;
var ucl_r=f.D4*cl_r;
var lcl_r=Math.max(0,f.D3*cl_r);
var sigma1=spanX/3;
var sigma2=spanX*2/3;
var plus1=cl_x+sigma1;
var minus1=cl_x-sigma1;
var plus2=cl_x+sigma2;
var minus2=cl_x-sigma2;
var xLevels=[];
var xReasons=[];
var rLevels=[];
var rReasons=[];
for(var i=0;i<means.length;i++){xLevels.push(0);xReasons.push([]);rLevels.push(0);rReasons.push([]);}
for(var i=0;i<means.length;i++){
  if(means[i]>ucl_x||means[i]<lcl_x){promote(xLevels,xReasons,i,3,'beyond limit');}
}
for(var i=2;i<means.length;i++){
  var hi=[]; var lo=[];
  for(var j=i-2;j<=i;j++){
    if(means[j]>plus2)hi.push(j);
    if(means[j]<minus2)lo.push(j);
  }
  if(hi.length>=2){for(var h=0;h<hi.length;h++)promote(xLevels,xReasons,hi[h],2,'2 of 3 beyond 2σ');}
  if(lo.length>=2){for(var h=0;h<lo.length;h++)promote(xLevels,xReasons,lo[h],2,'2 of 3 beyond 2σ');}
}
for(var i=6;i<means.length;i++){
  var above=true; var below=true;
  for(var j=i-6;j<=i;j++){
    if(!(means[j]>cl_x))above=false;
    if(!(means[j]<cl_x))below=false;
  }
  if(above||below){for(var j=i-6;j<=i;j++)promote(xLevels,xReasons,j,1,'run on one side');}
}
for(var i=0;i<ranges.length;i++){
  if(ranges[i]>ucl_r||ranges[i]<lcl_r){promote(rLevels,rReasons,i,3,'beyond limit');}
}
var xRulePoints=[];
var rRulePoints=[];
for(var i=0;i<means.length;i++){
  if(xLevels[i]>0){
    var color=xLevels[i]===3?'#d84a4a':(xLevels[i]===2?'#f28e2b':'#f6c344');
    xRulePoints.push({name:xReasons[i].join(' / '),value:Number(means[i].toFixed(2)),coord:[ids[i],means[i]],symbol:'circle',symbolSize:xLevels[i]===3?14:12,itemStyle:{color:color,borderColor:'#ffffff',borderWidth:2}});
  }
  if(rLevels[i]>0){
    rRulePoints.push({name:rReasons[i].join(' / '),value:Number(ranges[i].toFixed(2)),coord:[ids[i],ranges[i]],symbol:'circle',symbolSize:14,itemStyle:{color:'#d84a4a',borderColor:'#ffffff',borderWidth:2}});
  }
}
var xExtent=minmax(means.concat([ucl_x,lcl_x,plus2,minus2,plus1,minus1,cl_x]));
var rExtent=minmax(ranges.concat([ucl_r,lcl_r,cl_r]));
var xPad=Math.max((xExtent[1]-xExtent[0])*0.14,0.7);
var rPad=Math.max((rExtent[1]-rExtent[0])*0.16,0.8);
var yMinX=xExtent[0]-xPad;
var yMaxX=xExtent[1]+xPad;
var yMinR=Math.max(0,rExtent[0]-rPad);
var yMaxR=rExtent[1]+rPad;
transformedData={ids:ids,means:means,ranges:ranges,subgroup_size:n,cl_x:cl_x,ucl_x:ucl_x,lcl_x:lcl_x,cl_r:cl_r,ucl_r:ucl_r,lcl_r:lcl_r,plus1:plus1,minus1:minus1,plus2:plus2,minus2:minus2,xRulePoints:xRulePoints,rRulePoints:rRulePoints,yMinX:yMinX,yMaxX:yMaxX,yMinR:yMinR,yMaxR:yMaxR};
